/// <summary>
/// Static method to initialize new fields for the ETGSPAIN model.
/// </summary>
/// <param name="_InventValueReportTmpLine">InventValueReportTmpLine record.</param>
public void ETGSPAINPreWriteInventValueReportTmpLine()
{
    if (this.InventLocationId)
    {                    
        InventLocation              inventLocation          = InventLocation::find(this.InventLocationId);
        LogisticsPostalAddress      logisticsPostalAddress  = inventLocation.logisticsPostalAddress();
        LogisticsAddressCity        logisticsAddressCity    = LogisticsAddressCity::findRecId(logisticsPostalAddress.CityRecId);
        LogisticsAddressCityName    cityName                = logisticsAddressCity.Name;

        this.ETGSPAINInventLocationAdressCity    = cityName; //InventLocation::find(this.InventLocationId).logisticsPostalAddress().City;
    }

    if (this.InventBatchId)
    {
        this.ETGSPAINPurchOperationName         = ETGSPAINPurchOperationTable::find(this.InventBatchId).Name;
    }
}

/// <summary>
/// Extension of the <c>modifiedField</c> method.
/// </summary>
/// <param name="_fieldId">Modified field.</param>
public void modifiedField(fieldId _fieldId)
{
    next modifiedField(_fieldId);

    switch(_fieldId)
    {
        case fieldNum(InventValueReportTmpLine, InventLocationId):
        case fieldNum(InventValueReportTmpLine, InventBatchId):
                this.ETGSPAINPreWriteInventValueReportTmpLine();
                break;
    }
}
